#include<bits/stdc++.h>
using namespace std;
long long mp[21][21],n,m,dp[21][21][65536];
bool vis[21][21][65536];
long long dfs(long long x,long long d,long long s)
{
    if(vis[x][d][s])
    {
        return dp[x][d][s];
    }
    vis[x][d][s]=1;
    if(s==0)
    {
        return dp[x][d][s]=0;
    }
    dp[x][d][s]=2e9;
    for(long long i=1;i<=n;i++)
    {
        if(mp[x][i]<1e9&&(s&(1<<(i-1))))
        {
            for(long long t=s;t;t=(t-1)&s)
            {
                if(t&(1<<(i-1)))
                {
                    dp[x][d][s]=min(dp[x][d][s],dfs(i,d+1,t-(1<<(i-1)))+dfs(x,d,s-t)+d*mp[x][i]);
                }
            }
        }
    }
    return dp[x][d][s];
}
int main()
{
    memset(mp,0x3f,sizeof(mp));
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=m;i++)
    {
        long long u,v,w;
        scanf("%lld%lld%lld",&u,&v,&w);
        mp[u][v]=mp[v][u]=min(mp[u][v],w);
    }
    long long ans=INT_MAX;
    for(long long i=1;i<=n;i++)
    {
        ans=min(ans,dfs(i,1,(((1<<n)-1)^(1<<(i-1)))));
    }
    printf("%lld",ans);
    return 0;
}
